final:
module full_adder(
    input wire a,
    input wire b,
    input wire cin,
    output wire sum,
    output wire cout
    );

wire bxora;
wire aandb;
wire axorb_and_cin;

xor (bxora, a, b);
xor (sum, bxora, cin);
and (aandb, a, b);
and (axorb_and_cin, bxora, cin);
or (cout, aandb, axorb_and_cin);

endmodule
